import json
import os
import re

def classify_edge(source_slug, target_slug, target_type, evidence_paragraph, valid_edge_types, staging_verbs):
    """
    Sophisticated edge classification based on prose analysis.
    Returns: (edge_type, confidence_tier) or (None, None)
    """
    valid_set = set(valid_edge_types)
    evidence_lower = evidence_paragraph.lower()

    # === Pattern Matching for Common Relationships ===

    # 1. DEFEATS / KILLS / DUELS patterns
    if target_type == 'character.human':
        # "unhorsed" - clear combat defeat
        if 'unhorsed' in evidence_lower and 'DEFEATS' in valid_set:
            return ('DEFEATS', 1)
        # "slain by" or "killed by" - the source was killed
        if ('slain by' in evidence_lower or 'killed by' in evidence_lower) and 'KILLED_BY' in valid_set:
            return ('KILLED_BY', 1)
        # "defeated" in tournament/duel context
        if 'defeated' in evidence_lower and ('tilt' in evidence_lower or 'duel' in evidence_lower or 'tournament' in evidence_lower or 'tourney' in evidence_lower):
            if 'DUELS' in valid_set:
                return ('DUELS', 2)
            elif 'DEFEATS' in valid_set:
                return ('DEFEATS', 2)

    # 2. TRAVELS_WITH - "accompanied by", "rode with", "traveled with", "in party"
    if target_type == 'character.human':
        for phrase in ['accompanied by', 'in his party', 'in her party', 'in their party', 'rode with', 'traveled with']:
            if phrase in evidence_lower and 'TRAVELS_WITH' in valid_set:
                return ('TRAVELS_WITH', 2)

    # 3. Battle/War participation - FIGHTS_IN
    if 'event.' in target_type and 'battle' in target_type.lower():
        # Look for combat indicators
        combat_words = ['slain', 'killed', 'fought', 'battled', 'participated', 'charged', 'confronted', 'fell', 'died', 'during the battle', 'in the battle']
        if any(word in evidence_lower for word in combat_words):
            if 'FIGHTS_IN' in valid_set:
                return ('FIGHTS_IN', 2)

    # 4. Event attendance - ATTENDS
    if 'event.' in target_type:
        # For non-battle events or generic attendance
        if 'participated' in evidence_lower or 'attended' in evidence_lower or 'present' in evidence_lower:
            if 'ATTENDS' in valid_set or 'PARTICIPATES_IN' in valid_set:
                return (('ATTENDS' if 'ATTENDS' in valid_set else 'PARTICIPATES_IN'), 2)

    # 5. OPPOSES - "against", "marched against", "fought against"
    if target_type == 'character.human':
        if any(x in evidence_lower for x in ['marched against', 'fought against', 'against the army']):
            if 'OPPOSES' in valid_set:
                return ('OPPOSES', 2)

    # 6. ALLIES_WITH - "supported", "joined", "allied with"
    if target_type in ('character.human', 'organization.faction'):
        if any(x in evidence_lower for x in ['supported', 'joined the', 'allied with', 'fought for']):
            if 'ALLIES_WITH' in valid_set:
                return ('ALLIES_WITH', 2)

    # 7. MEMBER_OF - faction/organization membership
    if target_type == 'organization.faction':
        if any(x in evidence_lower for x in ['member of', 'part of', 'joined']):
            if 'MEMBER_OF' in valid_set:
                return ('MEMBER_OF', 2)

    # 8. LOCATED_AT - location in narrative (but not heraldry/description)
    if target_type == 'place.location':
        # Exclude heraldic references like "shield bore"
        if 'shield bore' not in evidence_lower and 'heraldry' not in evidence_lower:
            if 'LOCATED_AT' in valid_set:
                return ('LOCATED_AT', 2)

    # No clear relationship found
    return (None, None)

def process_candidates(input_path, output_path):
    """Process candidates and emit edges or rejections."""
    candidates = []

    try:
        with open(input_path, 'r') as f:
            for line in f:
                if line.strip():
                    candidates.append(json.loads(line))
    except Exception as e:
        print(f"Error reading {input_path}: {e}")
        return 0

    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    decisions = []

    for candidate in candidates:
        source_slug = candidate.get('source_slug')
        target_slug = candidate.get('target_slug')
        target_type = candidate.get('target_type', '')
        evidence_paragraph = candidate.get('evidence_paragraph', '')
        source_section = candidate.get('source_section', '')
        valid_edge_types = candidate.get('valid_edge_types', [])
        staging_verbs = candidate.get('staging_verbs_present', [])

        # Skip year/date targets marked as characters
        if target_type == 'character.human' and re.match(r'\d+-ac$', target_slug or ''):
            decisions.append({
                "decision": "reject_just_mention",
                "candidate_kind": "source_target",
                "source_slug": source_slug,
                "target_slug": target_slug,
                "reason": "target-is-date-not-character"
            })
            continue

        # Classify the relationship
        edge_type, confidence_tier = classify_edge(
            source_slug, target_slug, target_type, evidence_paragraph, valid_edge_types, staging_verbs
        )

        if edge_type:
            # Emit edge
            decisions.append({
                "decision": "emit_edge",
                "candidate_kind": "source_target",
                "evidence_kind": "wiki-entity",
                "source_slug": source_slug,
                "target_slug": target_slug,
                "edge_type": edge_type,
                "evidence_snippet": evidence_paragraph[:200] if len(evidence_paragraph) > 200 else evidence_paragraph,
                "evidence_section": source_section,
                "confidence_tier": confidence_tier
            })
        else:
            # Reject
            decisions.append({
                "decision": "reject_just_mention",
                "candidate_kind": "source_target",
                "source_slug": source_slug,
                "target_slug": target_slug,
                "reason": "no-fitting-relationship-in-prose"
            })

    # Write output
    if decisions:
        with open(output_path, 'w') as f:
            for decision in decisions:
                f.write(json.dumps(decision) + '\n')

    return len(decisions)

